content.problemStatement:
What will be the output of the following C++ program?

```cpp
#include 
using namespace std;

class Animal {
public:
    void eat() {
        cout << "Animal is eating." << endl;
    }
};

class Dog : public Animal {
public:
    void bark() {
        cout << "Dog is barking." << endl;
    }
};

int main() {
    Dog d;
    d.bark();
    d.eat();
    return 0;
}
```

